// =============================================================
// Europe eBird Cache Refresh — single-node implementation.
// =============================================================
// Strategy: per-country call to eBird's NOTABLE endpoint.
//   - Notable obs are eBird's own "rare for region" filter.
//   - This is exactly what we want for boosting rare species
//     in Estonia: if it's notable in a neighbour, it's likely
//     a candidate vagrant/migrant near Estonia.
//   - Volume: typically 50–500 obs per country per 7 days.
//   - 7 countries × 1 request = 7 eBird API calls per refresh.
//
// Source of truth for species_name <-> ebirdCode:
//   public Supabase storage at bird-avatars/meta/species_meta_v1.json
//
// Output: builds an array of upsert rows ready for the Supabase
//   insert-europe-ebird-cache Edge Function.
// =============================================================

const EBIRD_TOKEN = '9s72dc2jcjlq'; // shared linnuliigid token
const COUNTRIES   = ['FI','SE','LV','LT','PL','BY','RU'];
const META_URL    = 'https://eenwcyuyugyrjgpivxrq.supabase.co/storage/v1/object/public/bird-avatars/meta/species_meta_v1.json';

const SEVEN_DAYS_MS = 7 * 86400 * 1000;
const nowMs = Date.now();
const sevenDaysAgo = nowMs - SEVEN_DAYS_MS;

function safeNum(v) {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}

function parseObsDateMs(s) {
  const ymd = String(s || '').slice(0, 10);
  if (!/^\d{4}-\d{2}-\d{2}$/.test(ymd)) return null;
  const ms = Date.parse(ymd + 'T12:00:00Z');
  return Number.isFinite(ms) ? ms : null;
}

// -----------------------------------------------------------
// Step 1 — fetch species_meta to build code -> name map
// -----------------------------------------------------------
let codeToName = {};
try {
  const metaResp = await fetch(META_URL);
  if (!metaResp.ok) throw new Error('species_meta HTTP ' + metaResp.status);
  const meta = await metaResp.json();
  const items = (meta && meta.items && typeof meta.items === 'object') ? meta.items : {};
  for (const [name, item] of Object.entries(items)) {
    const code = (item && typeof item.ebirdCode === 'string') ? item.ebirdCode.trim() : '';
    const cleanName = String(name || '').trim();
    if (code && cleanName) codeToName[code] = cleanName;
  }
} catch (e) {
  return [{ json: { ok: false, error: 'species_meta_fetch_failed', detail: String(e && e.message || e) } }];
}

const trackedCodeCount = Object.keys(codeToName).length;
if (trackedCodeCount === 0) {
  return [{ json: { ok: false, error: 'no_tracked_species', detail: 'codeToName is empty' } }];
}

// -----------------------------------------------------------
// Step 2 — per-country eBird notable fetch + aggregation
// -----------------------------------------------------------
const allRows = [];
const perCountryStats = {};
const errors = [];

for (const cc of COUNTRIES) {
  const url = `https://api.ebird.org/v2/data/obs/${cc}/recent/notable?back=7&maxResults=10000&detail=simple`;
  let obs = [];
  try {
    const r = await fetch(url, {
      headers: { 'X-eBirdApiToken': EBIRD_TOKEN, 'Accept': 'application/json' },
    });
    if (!r.ok) {
      errors.push({ cc, status: r.status, snippet: (await r.text()).slice(0, 200) });
      perCountryStats[cc] = { fetched: 0, tracked: 0, rows: 0, error: 'HTTP ' + r.status };
      continue;
    }
    obs = await r.json();
    if (!Array.isArray(obs)) obs = [];
  } catch (e) {
    errors.push({ cc, error: String(e && e.message || e) });
    perCountryStats[cc] = { fetched: 0, tracked: 0, rows: 0, error: 'fetch_failed' };
    continue;
  }

  const bySpecies = {};
  let trackedCount = 0;
  for (const o of obs) {
    const code = String(o && o.speciesCode || '').trim();
    if (!code) continue;
    const dateMs = parseObsDateMs(o && o.obsDt);
    if (dateMs == null) continue;
    if (dateMs < sevenDaysAgo) continue;

    if (!bySpecies[code]) bySpecies[code] = { count: 0, latestMs: 0, latest: null };
    bySpecies[code].count++;
    if (dateMs > bySpecies[code].latestMs) {
      bySpecies[code].latestMs = dateMs;
      bySpecies[code].latest = o;
    }
  }

  for (const [code, agg] of Object.entries(bySpecies)) {
    const speciesName = codeToName[code];
    if (!speciesName) continue;
    trackedCount++;
    const latest = agg.latest || {};
    allRows.push({
      species_name: speciesName,
      country_code: cc,
      occ7: agg.count,
      latest_obs_date: String(latest.obsDt || '').slice(0, 10) || null,
      latest_lat: safeNum(latest.lat),
      latest_lon: safeNum(latest.lng),
      latest_loc: typeof latest.locName === 'string' ? latest.locName.slice(0, 500) : null,
    });
  }

  perCountryStats[cc] = {
    fetched: obs.length,
    tracked: trackedCount,
    rows: trackedCount,
  };
}

return [{
  json: {
    ok: true,
    rows: allRows,
    totalRows: allRows.length,
    countries: COUNTRIES.length,
    trackedCodeCount,
    perCountryStats,
    errors,
    runAt: new Date().toISOString(),
  },
}];
